mapper.select:
SELECT DISTINCT sp.id, sp.name, sp.url AS link_url, COALESCE(NULLIF(sp.path, ''), NULLIF(sp.code, '')) AS path, NULL AS priority, NULL AS icon, sp.code, NULL AS description, CAST(NULLIF(sp.parent_id, '') AS SIGNED) AS parent_menu_id, NULL AS level, sp.enabled AS is_enable, sp.group_name FROM sys_permission sp INNER JOIN sys_role_permission srp ON sp.id = srp.permission_id INNER JOIN sys_role sr ON sr.id = srp.role_id WHERE sr.code IN
#{roleCode}
AND sp.enabled = 1 AND COALESCE(NULLIF(sp.path, ''), NULLIF(sp.code, '')) IS NOT NULL ORDER BY sp.id

SELECT sp.id, sp.name, sp.url AS link_url, COALESCE(NULLIF(sp.path, ''), NULLIF(sp.code, '')) AS path, NULL AS priority, NULL AS icon, sp.code, NULL AS description, CAST(NULLIF(sp.parent_id, '') AS SIGNED) AS parent_menu_id, NULL AS level, sp.enabled AS is_enable, sp.group_name FROM sys_permission sp WHERE sp.id IN
#{menuId}
AND sp.enabled = 1 ORDER BY sp.id
